以下代码输出什么？请解释原因。

```go
func main() {
    s := []int{1, 2, 3}
    modify(s)
    fmt.Println(s)

    grow(s)
    fmt.Println(s)
}

func modify(s []int) {
    s[0] = 100
}

func grow(s []int) {
    s = append(s, 4)
    s[0] = 999
}
```

